package il.co.dcd.composermapper.parser; import il.co.dcd.composermapper.model.*; import il.co.dcd.composermapper.util.XmlUtil; import org.w3c.dom.*; import java.nio.file.Path; import java.util.*;
public class OperationFileParser {
  public List<OperationDef> parse(Path xml){ List<OperationDef> out=new ArrayList<>(); walk(XmlUtil.parse(xml).getDocumentElement(), xml, out); return out; }
  private void walk(Element e, Path xml, List<OperationDef> out){ if("CCDSEServerOperation".equals(e.getTagName())) out.add(parseOperation(e,xml)); for(Element c:XmlUtil.childElements(e)) walk(c,xml,out); }
  private OperationDef parseOperation(Element e, Path xml){ OperationDef op=new OperationDef(); op.setId(XmlUtil.attr(e,"id")); op.setOperationContext(XmlUtil.attr(e,"operationContext")); op.setSourceFile(xml); for(int i=0;i<e.getAttributes().getLength();i++){ var a=e.getAttributes().item(i); op.getRawAttributes().put(a.getNodeName(),a.getNodeValue()); } for(Element c:XmlUtil.childElements(e)){ switch(c.getTagName()){ case "opStep" -> op.getSteps().add(parseStep(c,op.getId(),xml)); case "refFormat" -> { String n=XmlUtil.attr(c,"name"), r=XmlUtil.attr(c,"refid"); if(n!=null&&r!=null) op.getRefFormats().put(n,r);} case "fmtDef" -> { String id=XmlUtil.attr(c,"id"); if(id!=null&&!id.isBlank()) op.getInlineFormatIds().add(id);} } } return op; }
  private OpStepDef parseStep(Element e, String opId, Path xml){ OpStepDef s=new OpStepDef(); s.setId(XmlUtil.attr(e,"id")); s.setParentOperationId(opId); s.setImplClass(XmlUtil.attr(e,"implClass")); s.setSourceFile(xml); for(int i=0;i<e.getAttributes().getLength();i++){ var a=e.getAttributes().item(i); s.getRawAttributes().put(a.getNodeName(),a.getNodeValue()); if(a.getNodeName().startsWith("on")&&a.getNodeName().endsWith("Do")) s.getTransitions().put(a.getNodeName(),a.getNodeValue()); } return s; }
}
